section.code:
{
  "$schema": "http://json-schema.org/draft-07/schema#",
  "$id": "https://faion.net/schemas/user-research-at-scale.json",
  "title": "User Research at Scale",
  "type": "object",
  "required": [
    "artefact_id",
    "intake_pipeline",
    "agent_tagging_rules",
    "clustering_strategy",
    "human_verification_sample",
    "repository_spec",
    "evidence",
    "owner",
    "last_touched",
    "template_version"
  ],
  "properties": {
    "artefact_id": {
      "type": "string",
      "description": "slug + ISO date",
      "minLength": 1
    },
    "intake_pipeline": {
      "type": "object",
      "description": "session capture -> transcription -> queue"
    },
    "agent_tagging_rules": {
      "type": "array",
      "description": "tag taxonomy + LLM tagging prompts",
      "minItems": 1
    },
    "clustering_strategy": {
      "type": "object",
      "description": "embedding model + cluster review cadence"
    },
    "human_verification_sample": {
      "type": "object",
      "description": "10%% review policy + reviewer roster"
    },
    "repository_spec": {
      "type": "object",
      "description": "schema + access control for the SSOT"
    },
    "evidence": {
      "type": "array",
      "description": "{source, citation}",
      "minItems": 1
    },
    "owner": {
      "type": "string",
      "description": "single named owner; generic group terms forbidden",
      "minLength": 1
    },
    "last_touched": {
      "type": "string",
      "description": "ISO-8601 timestamp",
      "format": "date-time"
    },
    "template_version": {
      "type": "string",
      "description": "semver matching methodology frontmatter at write time"
    }
  },
  "additionalProperties": false
}
